mkdir -p /tmp_workspace/results && python3 << 'PYEOF'
import json
import re
from datetime import datetime, timedelta, timezone
from zoneinfo import ZoneInfo

# ============================================================
# CONFIG / CONSTANTS
# ============================================================
TZ = ZoneInfo("Asia/Shanghai")
UTC = timezone.utc

LUNCH_START_LOCAL = (12, 0)  # HH, MM in local TZ
LUNCH_END_LOCAL   = (13, 0)

MAX_MEETINGS_PER_ATTENDEE_PER_DAY = 4

PRIORITY_WEIGHT = {"P0": 5, "P1": 3, "P2": 1}

# Attendee unavailability: {email: [(weekday_int 0=Mon, start_local_min, end_local_min)]}
# weekday: Monday=0, Tuesday=1, Wednesday=2, Thursday=3, Friday=4, Saturday=5, Sunday=6
ATTENDEE_UNAVAILABILITY = {
    "alice@example.com": [(2, 0, 24*60)],         # Wednesday all day (0:00-23:59)
    "frank@example.com": [(4, 17*60, 24*60)],     # Friday 17:00-23:59
    "grace@example.com": [(1, 9*60, 10*60)],      # Tuesday 09:00-10:00
}


def to_local(dt_utc):
    """Convert UTC datetime to Asia/Shanghai."""
    return dt_utc.astimezone(TZ)

def to_utc(dt_local):
    """Convert local (Asia/Shanghai) datetime to UTC."""
    return dt_local.astimezone(UTC)

def parse_ics_dt(s):
    """Parse ICS DTSTART/DTEND (basic UTC Z format)."""
    s = s.strip()
    if s.endswith('Z'):
        return datetime.strptime(s, "%Y%m%dT%H%M%SZ").replace(tzinfo=UTC)
    # try naive → assume UTC
    return datetime.strptime(s, "%Y%m%dT%H%M%S").replace(tzinfo=UTC)

def parse_iso(s):
    """Parse ISO8601 with offset."""
    # Python 3.7+ fromisoformat doesn't handle +08:00 in all versions
    # Use manual parsing
    s = s.strip()
    if s.endswith('Z'):
        return datetime.fromisoformat(s[:-1]).replace(tzinfo=UTC)
    # Handle offset like +08:00
    if '+' in s[10:] or (s[10:].count('-') > 0):
        # Find the offset
        for i in range(len(s)-1, 10, -1):
            if s[i] in ('+', '-'):
                dt_part = s[:i]
                off_part = s[i:]
                sign = 1 if off_part[0] == '+' else -1
                hh, mm = int(off_part[1:3]), int(off_part[4:6])
                offset = timezone(timedelta(hours=sign*hh, minutes=sign*mm))
                dt = datetime.fromisoformat(dt_part).replace(tzinfo=offset)
                return dt.astimezone(UTC)
    return datetime.fromisoformat(s).replace(tzinfo=UTC)

# ============================================================
# PARSE CALENDAR.ICS
# ============================================================
with open('/tmp_workspace/calendar.ics') as f:
    ics_raw = f.read()

# Extract VEVENTs
vevent_pattern = re.compile(r'BEGIN:VEVENT(.*?)END:VEVENT', re.DOTALL)

original_events = []  # list of dicts with utc times
for m in vevent_pattern.finditer(ics_raw):
    block = m.group(1)
    ev = {}
    ev['raw'] = m.group(0)
    for line in block.splitlines():
        line = line.strip()
        if line.startswith('DTSTART:'):
            ev['start_utc'] = parse_ics_dt(line[8:])
        elif line.startswith('DTEND:'):
            ev['end_utc'] = parse_ics_dt(line[6:])
        elif line.startswith('SUMMARY:'):
            ev['summary'] = line[8:]
        elif line.startswith('ATTENDEE:'):
            ev.setdefault('attendees', []).append(line.split('mailto:')[-1])
        elif line.startswith('UID:'):
            ev['uid'] = line[4:]
    original_events.append(ev)

print(f"Parsed {len(original_events)} original events")

# Compute per-attendee per-day meeting counts from existing calendar
# Key: (email, date_local_str)
attendee_day_count = {}

def local_date_str(dt_utc):
    return to_local(dt_utc).strftime('%Y-%m-%d')

for ev in original_events:
    day = local_date_str(ev['start_utc'])
    for att in ev.get('attendees', []):
        key = (att, day)
        attendee_day_count[key] = attendee_day_count.get(key, 0) + 1

print("Existing meeting counts by attendee/day:")
for k, v in sorted(attendee_day_count.items()):
    if v > 0:
        print(f"  {k}: {v}")

# ============================================================
# LOAD MEETING REQUESTS
# ============================================================
with open('/tmp_workspace/meeting_requests.json') as f:
    requests_raw = json.load(f)

# Parse windows to UTC
for req in requests_raw:
    req['windows_utc'] = []
    for w in req['preferred_windows']:
        req['windows_utc'].append({
            'start': parse_iso(w['start']),
            'end':   parse_iso(w['end']),
        })

# ============================================================
# BUILD BUSY INTERVALS per attendee (from original events)
# ============================================================
# attendee_busy: {email: [(start_utc, end_utc), ...]}
attendee_busy = {}

def add_busy(email, start, end):
    attendee_busy.setdefault(email, []).append((start, end))

for ev in original_events:
    for att in ev.get('attendees', []):
        add_busy(att, ev['start_utc'], ev['end_utc'])

def overlaps(s1, e1, s2, e2):
    """True if [s1,e1) overlaps [s2,e2)."""
    return s1 < e2 and s2 < e1

def is_attendee_free(email, start_utc, end_utc, scheduled_events):
    """Check if attendee has no conflicts in existing + newly scheduled events."""
    # Check original busy
    for bs, be in attendee_busy.get(email, []):
        if overlaps(start_utc, end_utc, bs, be):
            return False
    # Check newly scheduled
    for ev in scheduled_events:
        if email in ev['attendees']:
            if overlaps(start_utc, end_utc, ev['start_utc'], ev['end_utc']):
                return False
    return True

def is_during_lunch(start_utc, end_utc):
    """Check if the meeting overlaps with lunch break (12:00-13:00 local)."""
    # Lunch defined per local day of start
    start_local = to_local(start_utc)
    # Compute lunch window for that day
    lunch_start = start_local.replace(hour=12, minute=0, second=0, microsecond=0)
    lunch_end   = start_local.replace(hour=13, minute=0, second=0, microsecond=0)
    lunch_start_utc = to_utc(lunch_start)
    lunch_end_utc   = to_utc(lunch_end)
    return overlaps(start_utc, end_utc, lunch_start_utc, lunch_end_utc)

def is_attendee_unavailable(email, start_utc, end_utc):
    """Check per-attendee unavailability rules."""
    if email not in ATTENDEE_UNAVAILABILITY:
        return False
    start_local = to_local(start_utc)
    end_local   = to_local(end_utc)
    weekday = start_local.weekday()  # 0=Mon
    for (wd, unav_start_min, unav_end_min) in ATTENDEE_UNAVAILABILITY[email]:
        if weekday == wd:
            # Convert meeting to local minutes from midnight
            meeting_start_min = start_local.hour * 60 + start_local.minute
            meeting_end_min   = end_local.hour * 60 + end_local.minute
            # Handle end_utc potentially crossing midnight; use date check
            # If end is next day, end_min effectively > 1440 but just use 24*60
            if to_local(end_utc).date() != start_local.date():
                meeting_end_min = 24*60
            if overlaps(meeting_start_min, meeting_end_min, unav_start_min, unav_end_min):
                return True
    return False

def can_schedule(req, start_utc, end_utc, scheduled_events, attendee_day_count_copy):
    """Full constraint check for scheduling a meeting at given time."""
    # 1. Lunch break
    if is_during_lunch(start_utc, end_utc):
        return False, "time_conflict", "Meeting overlaps with lunch break (12:00-13:00)"

    day = local_date_str(start_utc)

    # 2. Attendee availability & daily limit
    for email in req['required_attendees']:
        # Per-attendee unavailability
        if is_attendee_unavailable(email, start_utc, end_utc):
            return False, "attendee_unavailable", f"{email} is marked unavailable during this time"
        # Time conflicts
        if not is_attendee_free(email, start_utc, end_utc, scheduled_events):
            return False, "time_conflict", f"{email} has a conflicting meeting"
        # Daily limit
        count = attendee_day_count_copy.get((email, day), 0)
        if count >= MAX_MEETINGS_PER_ATTENDEE_PER_DAY:
            return False, "daily_limit_exceeded", f"{email} already has {count} meetings on {day}"

    return True, None, None

def find_slot(req, scheduled_events, attendee_day_count_copy):
    """
    Try to find a valid slot within preferred windows.
    Returns (start_utc, end_utc) or None.
    Prefers P0 → earliest slot.
    """
    duration = timedelta(minutes=req['duration_minutes'])
    best_slot = None

    for window in req['windows_utc']:
        win_start = window['start']
        win_end   = window['end']

        # Slide a slot within the window in 15-minute increments
        slot_start = win_start
        while slot_start + duration <= win_end:
            slot_end = slot_start + duration
            ok, _, _ = can_schedule(req, slot_start, slot_end, scheduled_events, attendee_day_count_copy)
            if ok:
                if best_slot is None:
                    best_slot = (slot_start, slot_end)
                # For P0, prefer earliest
                if req['priority'] == 'P0':
                    return best_slot
                # Otherwise take first found
                return best_slot
            slot_start += timedelta(minutes=15)

    return None

# ============================================================
# SCHEDULING ALGORITHM
# Sort by priority weight desc, then process greedily
# ============================================================
sorted_requests = sorted(requests_raw, 
    key=lambda r: (-PRIORITY_WEIGHT[r['priority']], r['id']))

scheduled_events = []   # newly scheduled
scheduled_ids = set()
unscheduled = []

# Work with a mutable copy of counts
working_counts = dict(attendee_day_count)

def update_counts(req, start_utc):
