import json
import re
from datetime import datetime, timedelta, timezone
from zoneinfo import ZoneInfo

# ============================================================
# CONFIG / CONSTANTS
# ============================================================
TZ = ZoneInfo("Asia/Shanghai")
UTC = timezone.utc

PRIORITY_WEIGHT = {"P0": 5, "P1": 3, "P2": 1}
MAX_MEETINGS_PER_ATTENDEE_PER_DAY = 4

# Attendee unavailability: {email: [(weekday_int 0=Mon, start_min, end_min)]}
ATTENDEE_UNAVAILABILITY = {
    "alice@example.com": [(2, 0, 24*60)],       # Wednesday all day
    "frank@example.com": [(4, 17*60, 24*60)],   # Friday 17:00+
    "grace@example.com": [(1, 9*60, 10*60)],    # Tuesday 09:00-10:00
}

PRIORITY_ICS = {"P0": "1", "P1": "5", "P2": "9"}


def to_local(dt_utc):
    return dt_utc.astimezone(TZ)

def to_utc(dt_local):
    return dt_local.astimezone(UTC)

def local_date_str(dt_utc):
    return to_local(dt_utc).strftime('%Y-%m-%d')

def parse_ics_dt(s):
    s = s.strip()
    if s.endswith('Z'):
        return datetime.strptime(s, "%Y%m%dT%H%M%SZ").replace(tzinfo=UTC)
    return datetime.strptime(s, "%Y%m%dT%H%M%S").replace(tzinfo=UTC)

def parse_iso(s):
    s = s.strip()
    if s.endswith('Z'):
        return datetime.fromisoformat(s[:-1]).replace(tzinfo=UTC)
    # Find sign of offset after position 10 (after the date part)
    for i in range(len(s)-1, 10, -1):
        if s[i] in ('+', '-'):
            dt_part = s[:i]
            off_part = s[i:]
            sign = 1 if off_part[0] == '+' else -1
            hh, mm = int(off_part[1:3]), int(off_part[4:6])
            offset = timezone(timedelta(hours=sign*hh, minutes=sign*mm))
            dt = datetime.fromisoformat(dt_part).replace(tzinfo=offset)
            return dt.astimezone(UTC)
    return datetime.fromisoformat(s).replace(tzinfo=UTC)

def overlaps(s1, e1, s2, e2):
    """True if [s1,e1) overlaps [s2,e2)."""
    return s1 < e2 and s2 < e1

def dt_to_ics_utc(dt):
    return dt.strftime("%Y%m%dT%H%M%SZ")


# ============================================================
# PARSE CALENDAR.ICS
# ============================================================
with open('/tmp_workspace/calendar.ics') as f:
    ics_raw = f.read()

vevent_pattern = re.compile(r'BEGIN:VEVENT(.*?)END:VEVENT', re.DOTALL)

original_events = []
for m in vevent_pattern.finditer(ics_raw):
    block = m.group(1)
    ev = {'raw': m.group(0), 'attendees': []}
    for line in block.splitlines():
        line = line.strip()
        if line.startswith('DTSTART:'):
            ev['start_utc'] = parse_ics_dt(line[8:])
        elif line.startswith('DTEND:'):
            ev['end_utc'] = parse_ics_dt(line[6:])
        elif line.startswith('SUMMARY:'):
            ev['summary'] = line[8:]
        elif line.startswith('ATTENDEE:'):
            ev['attendees'].append(line.split('mailto:')[-1])
        elif line.startswith('UID:'):
            ev['uid'] = line[4:]
    original_events.append(ev)

print(f"Parsed {len(original_events)} original events")

# ============================================================
# BUILD BUSY INTERVALS & DAY COUNTS from original calendar
# ============================================================
attendee_busy = {}  # {email: [(start_utc, end_utc)]}
attendee_day_count = {}  # {(email, day_str): count}

for ev in original_events:
    day = local_date_str(ev['start_utc'])
    for att in ev['attendees']:
        attendee_busy.setdefault(att, []).append((ev['start_utc'], ev['end_utc']))
        key = (att, day)
        attendee_day_count[key] = attendee_day_count.get(key, 0) + 1

print("Existing attendee/day counts:")
for k, v in sorted(attendee_day_count.items()):
    print(f"  {k}: {v}")

# ============================================================
# CONFLICT DETECTION IN ORIGINAL CALENDAR
# ============================================================
print("\n=== Original Calendar Conflict Check ===")
conflicts_found = []
for i, ev1 in enumerate(original_events):
    for j, ev2 in enumerate(original_events):
        if j <= i:
            continue
        shared = set(ev1['attendees']) & set(ev2['attendees'])
        if shared and overlaps(ev1['start_utc'], ev1['end_utc'], ev2['start_utc'], ev2['end_utc']):
            conflicts_found.append((ev1['summary'], ev2['summary'], shared))
            print(f"  CONFLICT: '{ev1['summary']}' vs '{ev2['summary']}' attendees: {shared}")
if not conflicts_found:
    print("  No conflicts in original calendar.")

# ============================================================
# LOAD MEETING REQUESTS
# ============================================================
with open('/tmp_workspace/meeting_requests.json') as f:
    requests_raw = json.load(f)

for req in requests_raw:
    req['windows_utc'] = [
        {'start': parse_iso(w['start']), 'end': parse_iso(w['end'])}
        for w in req['preferred_windows']
    ]

# ============================================================
# CONSTRAINT CHECKERS
# ============================================================
def is_during_lunch(start_utc, end_utc):
    """Overlaps with 12:00-13:00 local time."""
    start_local = to_local(start_utc)
    lunch_start = start_local.replace(hour=12, minute=0, second=0, microsecond=0)
    lunch_end   = start_local.replace(hour=13, minute=0, second=0, microsecond=0)
    return overlaps(start_utc, end_utc, to_utc(lunch_start), to_utc(lunch_end))

def is_attendee_unavailable(email, start_utc, end_utc):
    if email not in ATTENDEE_UNAVAILABILITY:
        return False
    start_local = to_local(start_utc)
    end_local   = to_local(end_utc)
    weekday = start_local.weekday()
    for (wd, unav_s, unav_e) in ATTENDEE_UNAVAILABILITY[email]:
        if weekday != wd:
            continue
        meet_s = start_local.hour * 60 + start_local.minute
        meet_e = end_local.hour * 60 + end_local.minute
        if end_local.date() != start_local.date():
            meet_e = 24 * 60
        if overlaps(meet_s, meet_e, unav_s, unav_e):
            return True
    return False

def attendee_has_conflict(email, start_utc, end_utc, scheduled_events):
    for (bs, be) in attendee_busy.get(email, []):
        if overlaps(start_utc, end_utc, bs, be):
            return True
    for ev in scheduled_events:
        if email in ev['attendees']:
            if overlaps(start_utc, end_utc, ev['start_utc'], ev['end_utc']):
                return True
    return False

def can_schedule(req, start_utc, end_utc, scheduled_events, day_counts):
    """Returns (ok, reason_code, reason_text)."""
    if is_during_lunch(start_utc, end_utc):
        return False, "time_conflict", "Meeting overlaps with lunch break (12:00-13:00 local)"

    day = local_date_str(start_utc)

    for email in req['required_attendees']:
        if is_attendee_unavailable(email, start_utc, end_utc):
            return False, "attendee_unavailable", \
                f"{email} is marked unavailable during this time slot"
        if attendee_has_conflict(email, start_utc, end_utc, scheduled_events):
            return False, "time_conflict", \
                f"{email} has a conflicting existing meeting"
        count = day_counts.get((email, day), 0)
        if count >= MAX_MEETINGS_PER_ATTENDEE_PER_DAY:
            return False, "daily_limit_exceeded", \
                f"{email} already has {count} meetings on {day} (limit={MAX_MEETINGS_PER_ATTENDEE_PER_DAY})"

    return True, None, None

def find_best_slot(req, scheduled_events, day_counts):
    """Find earliest valid slot within preferred windows. Returns (start_utc, end_utc) or None."""
    duration = timedelta(minutes=req['duration_minutes'])
    for window in req['windows_utc']:
        slot_start = window['start']
        while slot_start + duration <= window['end']:
            ok, _, _ = can_schedule(req, slot_start, slot_start + duration, scheduled_events, day_counts)
            if ok:
                return slot_start, slot_start + duration
            slot_start += timedelta(minutes=15)
    return None

def diagnose_failure(req, scheduled_events, day_counts):
    """Return (reason_code, reason_text) explaining why no slot is available."""
    duration = timedelta(minutes=req['duration_minutes'])
    all_failures = []

    for window in req['windows_utc']:
        slot_start = window['start']
        if slot_start + duration > window['end']:
            all_failures.append(("insufficient_duration_slot",
                f"Window {slot_start.strftime('%Y-%m-%d %H:%M')} UTC is too short for {req['duration_minutes']}min meeting"))
            continue
        while slot_start + duration <= window['end']:
            ok, code, msg = can_schedule(req, slot_start, slot_start + duration, scheduled_events, day_counts)
            if not ok:
                all_failures.append((code, msg))
            slot_start += timedelta(minutes=15)

    if not all_failures:
        return "unknown", "No slot found but no specific failure captured."

    # Pick most informative / first-priority code
    priority_order = ["attendee_unavailable", "daily_limit_exceeded", "time_conflict",
                      "insufficient_duration_slot", "outside_preferred_window"]
    for code in priority_order:
        matches = [f for f in all_failures if f[0] == code]
        if matches:
            return matches[0]

    return all_failures[0]


# ============================================================
# GREEDY SCHEDULER (highest priority first)
# ============================================================
sorted_reqs = sorted(requests_raw, key=lambda r: (-PRIORITY_WEIGHT[r['priority']], r['id']))

scheduled_events = []
decision_log = []
unscheduled = []
working_counts = dict(attendee_day_count)

print("\n=== Scheduling New Requests ===")
for req in sorted_reqs:
    rid = req['id']
    title = req['title']
    priority = req['priority']
    print(f"\nProcessing {rid} [{priority}] '{title}'")

    slot = find_best_slot(req, scheduled_events, working_counts)

    if slot:
        start_utc, end_utc = slot
        s_local = to_local(start_utc)
        e_local = to_local(end_utc)
        time_str = f"{s_local.strftime('%Y-%m-%d %H:%M')} - {e_local.strftime('%H:%M')} (CST +08:00)"

        ev = {
            'uid': rid + '@scheduler',
            'summary': title,
            'start_utc': start_utc,
            'end_utc': end_utc,
            'attendees': req['required_attendees'] + req.get('optional_attendees', []),
            'priority': priority,
            'req_id': rid,
        }
        scheduled_events.append(ev)

        day = local_date_str(start_utc)
        for email in req['required_attendees']:
            working_counts[(email, day)] = working_counts.get((email, day), 0) + 1
            # Also add to busy list for future conflict checks
            attendee_busy.setdefault(email, []).append((start_utc, end_utc))

        print(f"  ✓ Scheduled: {time_str}")
        decision_log.append({
            'id': rid, 'title': title, 'priority': priority,
            'status': 'scheduled', 'time': time_str,
        })
    else:
        code, text = diagnose_failure(req, scheduled_events, working_counts)
        print(f"  ✗ Unscheduled: {code} — {text}")
        unscheduled.append({'id': rid, 'title': title, 'reason_code': code, 'reason_text': text})
        decision_log.append({
            'id': rid, 'title': title, 'priority': priority,
            'status': 'unscheduled', 'reason_code': code, 'reason_text': text,
        })

total_weight = sum(PRIORITY_WEIGHT[e['priority']] for e in scheduled_events)
print(f"\n=== Summary ===")
print(f"Scheduled: {len(scheduled_events)} / 15")
print(f"Unscheduled: {len(unscheduled)}")
print(f"Total priority weight: {total_weight}")

# ============================================================
# WRITE scheduled.ics
# ============================================================
now_utc_str = dt_to_ics_utc(datetime.now(UTC))

new_blocks = []
for ev in scheduled_events:
    att_lines = "\n".join("ATTENDEE:mailto:" + a for a in ev['attendees'])
    prio_ics = PRIORITY_ICS.get(ev['priority'], '5')
    block = (
        "BEGIN:VEVENT\n"
        "UID:" + ev['uid'] + "\n"
        "DTSTAMP:" + now_utc_str + "\n"
        "DTSTART:" + dt_to_ics_utc(ev['start_utc']) + "\n"
        "DTEND:" + dt_to_ics_utc(ev['end_utc']) + "\n"
        "SUMMARY:" + ev['summary'] + "\n"
        "PRIORITY:" + prio_ics + "\n"
        + att_lines + "\n"
        "END:VEVENT"
    )
    new_blocks.append(block)

ics_out = ics_raw.rstrip()
if ics_out.endswith('END:VCALENDAR'):
    ics_out = ics_out[:-len('END:VCALENDAR')].rstrip()

ics_out += "\n\n" + "\n\n".join(new_blocks) + "\n\nEND:VCALENDAR\n"

with open('/tmp_workspace/results/scheduled.ics', 'w') as f:
    f.write(ics_out)
print("Wrote scheduled.ics")

# ============================================================
# WRITE unscheduled.json
# ============================================================
with open('/tmp_workspace/results/unscheduled.json', 'w') as f:
    json.dump(unscheduled, f, indent=2)
print("Wrote unscheduled.json")

# ============================================================
# WRITE decision_log.md
# ============================================================
sched_log = [d for d in decision_log if d['status'] == 'scheduled']
unsched_log = [d for d in decision_log if d['status'] == 'unscheduled']

lines = []
lines.append("### Scheduling Decision Log\n")
lines.append("### Summary")
lines.append(f"- Total requests: 15")
lines.append(f"- Scheduled: {len(scheduled_events)}")
lines.append(f"- Unscheduled: {len(unscheduled)}")
lines.append(f"- Total priority weight achieved: {total_weight}")
lines.append("")
lines.append("### High Priority Decisions")

# P0 decisions first
for d in decision_log:
    if d['priority'] != 'P0':
        continue
    if d['status'] == 'scheduled':
        lines.append(
            f"- **{d['id']} ({d['title']})** [P0] → Scheduled at {d['time']}. "
            f"Processed first due to highest priority (weight=5); attendee slots reserved before lower-priority requests."
        )
    else:
        lines.append(
            f"- **{d['id']} ({d['title']})** [P0] → **Could not schedule** — "
            f"`{d['reason_code']}`: {d['reason_text']}"
        )

# P1 tradeoff notes
for d in decision_log:
    if d['priority'] != 'P1':
        continue
    if d['status'] == 'scheduled':
        lines.append(
            f"- **{d['id']} ({d['title']})** [P1] → Scheduled at {d['time']}."
        )
    else:
        lines.append(
            f"- **{d['id']} ({d['title']})** [P1] → Unscheduled — "
            f"`{d['reason_code']}`: {d['reason_text']}"
        )

lines.append("")
lines.append("### Unscheduled Requests")

if unsched_log:
    for d in unsched_log:
        lines.append(
            f"- `{d['id']}` — [{d['priority']}] **{d['title']}**: "
            f"{d['reason_text']} (code: `{d['reason_code']}`)"
        )
else:
    lines.append("- None — all 15 requests were successfully scheduled.")

lines.append("")
lines.append("### All Scheduling Decisions")
for d in decision_log:
    icon = "✅" if d['status'] == 'scheduled' else "❌"
    if d['status'] == 'scheduled':
        lines.append(f"- {icon} `{d['id']}` [{d['priority']}] **{d['title']}** → {d['time']}")
    else:
        lines.append(
            f"- {icon} `{d['id']}` [{d['priority']}] **{d['title']}** "
            f"→ `{d['reason_code']}`: {d['reason_text']}"
        )

with open('/tmp_workspace/results/decision_log.md', 'w') as f:
    f.write("\n".join(lines) + "\n")
print("Wrote decision_log.md")

# ============================================================
# VALIDATION
# ============================================================
print("\n=== Validation ===")
ics_check = open('/tmp_workspace/results/scheduled.ics').read()
total_vevents = ics_check.count('BEGIN:VEVENT')
expected = 30 + len(scheduled_events)
status = "OK" if total_vevents == expected else f"MISMATCH expected {expected}"
print(f"VEVENTs in scheduled.ics: {total_vevents} ({status})")

print(f"\nScheduled ({len(scheduled_events)}):")
for ev in scheduled_events:
    s = to_local(ev['start_utc'])
    e = to_local(ev['end_utc'])
    print(f"  {ev['req_id']} [{ev['priority']}] {ev['summary']}")
    print(f"    {s.strftime('%a %Y-%m-%d %H:%M')} - {e.strftime('%H:%M')} CST")

print(f"\nUnscheduled ({len(unscheduled)}):")
for u in unscheduled:
    print(f"  {u['id']}: {u['reason_code']} — {u['reason_text']}")

