def is_during_lunch(start_utc, end_utc):
    """Overlaps with 12:00-13:00 local time."""
    start_local = to_local(start_utc)
    lunch_start = start_local.replace(hour=12, minute=0, second=0, microsecond=0)
    lunch_end   = start_local.replace(hour=13, minute=0, second=0, microsecond=0)
    return overlaps(start_utc, end_utc, to_utc(lunch_start), to_utc(lunch_end))

def is_attendee_unavailable(email, start_utc, end_utc):
    if email not in ATTENDEE_UNAVAILABILITY:
        return False
    start_local = to_local(start_utc)
    end_local   = to_local(end_utc)
    weekday = start_local.weekday()
    for (wd, unav_s, unav_e) in ATTENDEE_UNAVAILABILITY[email]:
        if weekday != wd:
            continue
        meet_s = start_local.hour * 60 + start_local.minute
        meet_e = end_local.hour * 60 + end_local.minute
        if end_local.date() != start_local.date():
            meet_e = 24 * 60
        if overlaps(meet_s, meet_e, unav_s, unav_e):
            return True
    return False

def attendee_has_conflict(email, start_utc, end_utc, scheduled_events):
    for (bs, be) in attendee_busy.get(email, []):
        if overlaps(start_utc, end_utc, bs, be):
            return True
    for ev in scheduled_events:
        if email in ev['attendees']:
            if overlaps(start_utc, end_utc, ev['start_utc'], ev['end_utc']):
                return True
    return False

def can_schedule(req, start_utc, end_utc, scheduled_events, day_counts):
    """Returns (ok, reason_code, reason_text)."""
    if is_during_lunch(start_utc, end_utc):
        return False, "time_conflict", "Meeting overlaps with lunch break (12:00-13:00 local)"

    day = local_date_str(start_utc)

    for email in req['required_attendees']:
        if is_attendee_unavailable(email, start_utc, end_utc):
            return False, "attendee_unavailable", \
                f"{email} is marked unavailable during this time slot"
        if attendee_has_conflict(email, start_utc, end_utc, scheduled_events):
            return False, "time_conflict", \
                f"{email} has a conflicting existing meeting"
        count = day_counts.get((email, day), 0)
        if count >= MAX_MEETINGS_PER_ATTENDEE_PER_DAY:
            return False, "daily_limit_exceeded", \
                f"{email} already has {count} meetings on {day} (limit={MAX_MEETINGS_PER_ATTENDEE_PER_DAY})"

    return True, None, None

def find_best_slot(req, scheduled_events, day_counts):
    """Find earliest valid slot within preferred windows. Returns (start_utc, end_utc) or None."""
    duration = timedelta(minutes=req['duration_minutes'])
    for window in req['windows_utc']:
        slot_start = window['start']
        while slot_start + duration <= window['end']:
            ok, _, _ = can_schedule(req, slot_start, slot_start + duration, scheduled_events, day_counts)
            if ok:
                return slot_start, slot_start + duration
            slot_start += timedelta(minutes=15)
    return None

def diagnose_failure(req, scheduled_events, day_counts):
    """Return (reason_code, reason_text) explaining why no slot is available."""
    duration = timedelta(minutes=req['duration_minutes'])
    all_failures = []

    for window in req['windows_utc']:
        slot_start = window['start']
        if slot_start + duration > window['end']:
            all_failures.append(("insufficient_duration_slot",
                f"Window {slot_start.strftime('%Y-%m-%d %H:%M')} UTC is too short for {req['duration_minutes']}min meeting"))
            continue
        while slot_start + duration <= window['end']:
            ok, code, msg = can_schedule(req, slot_start, slot_start + duration, scheduled_events, day_counts)
            if not ok:
                all_failures.append((code, msg))
            slot_start += timedelta(minutes=15)

    if not all_failures:
        return "unknown", "No slot found but no specific failure captured."

    # Pick most informative / first-priority code
    priority_order = ["attendee_unavailable", "daily_limit_exceeded", "time_conflict",
                      "insufficient_duration_slot", "outside_preferred_window"]
    for code in priority_order:
        matches = [f for f in all_failures if f[0] == code]
        if matches:
            return matches[0]

    return all_failures[0]


